# agent_planner.py
class PlannerAgent:
    def run(self, request: AgentRequest) -> Plan:
        flags = request.flag_snapshot

        # Release flag: use new multi-hop planner or legacy single-shot
        if flags.get("agent.research-subgraph.release"):
            return self._multi_hop_plan(request)
        return self._single_shot_plan(request)

    def _call_tool(self, tool: str, args: dict, flags: dict) -> dict:
        # Kill switch: check before every external tool call
        if flags.get("agent.tool-caller.kill"):
            raise ToolDisabledError(f"Tool calls disabled via kill switch")
        return self.tool_client.call(tool, args)

# Model A/B test via experiment flag
class ModelRouter:
    def __init__(self, flag_client: FlagClient):
        self.flag_client = flag_client

    def get_model(self, request: AgentRequest) -> str:
        variant = request.flag_snapshot.get(
            "agent.model-variant.experiment", "haiku"
        )
        models = {
            "haiku": "claude-3-haiku-20240307",
            "sonnet": "claude-3-sonnet-20240229",
        }
        return models[variant]

# Result: p99 latency 210ms (haiku) vs 430ms (sonnet)
# Quality score: 0.82 (haiku) vs 0.91 (sonnet)
# Decision: promote sonnet based on quality win

# No deploy needed — ops flag updated in LaunchDarkly UI
class CompletionClient:
    def complete(self, prompt: str, flags: dict) -> str:
        temperature = float(flags.get("agent.temperature.ops", 0.7))
        return self.llm.complete(
            prompt=prompt,
            temperature=temperature,  # Tunable at runtime
            max_tokens=2048,
        )
